INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Unified Contact Records$q$, $q$Combines email, calendar activity, and public social profile data into a single timeline for every contact and company.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Nimble Prospector Browser Extension$q$, $q$Surfaces contact and company details while browsing LinkedIn, X, and other sites, letting users add or update records without leaving the page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Deal Pipelines$q$, $q$Simple, visual pipelines for tracking deals through stages without the configuration overhead of enterprise sales tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Unified Inbox$q$, $q$Brings connected email accounts into the CRM so messages, contacts, and history stay linked in one place.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Group Messaging and Email Templates$q$, $q$Send segmented, templated email campaigns to contact groups directly from the CRM and track engagement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Calendar and Inbox Sync$q$, $q$Two-way syncing with Google Workspace and Microsoft 365 keeps meetings and messages tied to the correct contact automatically.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Contact Segmentation and Tagging$q$, $q$Organize contacts into lists and tags for targeted outreach, follow-up, and reporting.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Reporting and Activity Tracking$q$, $q$Basic dashboards and reports on deals, tasks, and team activity to monitor pipeline health.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Mobile Apps$q$, $q$iOS and Android apps let users look up contacts, log notes, and manage tasks while away from a desktop.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Task and Reminder Management$q$, $q$Built-in tasks and reminders help teams stay on top of follow-ups tied directly to contact and deal records.$q$, 9);
