INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$What is Nimble used for?$q$, $q$Nimble is a CRM that helps small businesses manage contacts, track deals, and stay on top of email and social interactions, enriching each contact record automatically with public profile and company data.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Does Nimble offer a free plan?$q$, $q$Nimble does not maintain an ongoing free tier; instead it offers a free trial period so teams can evaluate the platform before committing to a paid plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$What is Nimble Prospector?$q$, $q$Nimble Prospector is a browser extension that lets users view and capture contact and company information while browsing sites like LinkedIn, adding new records or updating existing ones without leaving the page.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Does Nimble integrate with Google Workspace and Microsoft 365?$q$, $q$Yes, Nimble offers two-way calendar and inbox syncing with both Google Workspace and Microsoft 365, keeping meetings and messages linked to the right contact record.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Is Nimble a good fit for large enterprises?$q$, $q$Nimble is designed primarily for small and mid-sized businesses; larger enterprises with complex sales processes or heavy customization needs may find its feature set too streamlined.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Relationship-driven sales outreach$q$, $q$Sales reps use Nimble to research prospects, capture social and company context, and track deals through simple pipeline stages.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Consultant and freelancer contact management$q$, $q$Independent consultants centralize client contacts, email history, and follow-up tasks in one lightweight tool.$q$, $q$Consultants and solopreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Segmented email outreach campaigns$q$, $q$Marketing teams tag and segment contact lists, then send templated group emails and track engagement from the same records.$q$, $q$Small business marketing teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Social selling and prospecting$q$, $q$Business development professionals use the browser extension to enrich and capture leads while browsing social platforms.$q$, $q$Business development and recruiting professionals$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Business (Monthly)$q$, $q$$29.90/user/month$q$, $q$Monthly$q$, $q$["Unified contact records","Nimble Prospector browser extension","Deal pipelines","Unified inbox","Mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Business (Annual)$q$, $q$$24.90/user/month$q$, $q$Annual$q$, $q$["All Business plan features","Discounted annual rate","Calendar and inbox sync","Group email templates","Reporting and activity tracking"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, $q$["Volume-based pricing for larger teams","Dedicated onboarding support","Advanced admin controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nimble is a relationship-focused CRM built for small and mid-sized businesses that want the organization of a sales database without the complexity of enterprise platforms. Rather than forcing teams to manually key in contact details, Nimble automatically pulls in social profiles, company information, and communication history so every contact record becomes a fuller picture of the relationship, not just a name and email address.$q$, $q$At its core, Nimble combines contact management, a unified inbox, simple deal pipelines, and lightweight workflow tools into a single web app. It syncs with Google Workspace and Microsoft 365 calendars and inboxes, and it layers a browser extension on top that lets users capture contact and company data from LinkedIn, X, and other sites they are already browsing, then push that information straight into the CRM.$q$, $q$The product is positioned as an alternative to heavier CRMs like Salesforce for teams that find those tools overbuilt for their needs. Nimble leans on a single straightforward pricing tier, a clean interface, and enrichment features that reduce manual data entry, making it a fit for founders, solo operators, and small sales or marketing teams who want a CRM that stays out of the way.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$who-nimble-is-for$q$, $q$Who Nimble Is For$q$, 2, ARRAY[$q$Nimble suits small businesses, solopreneurs, and small sales teams that need a central place to track contacts, deals, and conversations without hiring an administrator to configure and maintain the system. Its social enrichment and browser widget appeal especially to relationship-driven roles such as sales reps, recruiters, consultants, and business development professionals who spend a lot of time researching people and companies online before reaching out.$q$, $q$Marketing and communications teams that rely on segmented email outreach also benefit from Nimble's group messaging and templated email features, which sit inside the same tool where contact records and engagement history already live. Because the interface avoids heavy configuration, non-technical founders and small agency owners can get a working CRM running in a short setup window without a dedicated CRM administrator.$q$, $q$Teams already embedded in Google Workspace or Microsoft 365 tend to get the most value, since Nimble's calendar and inbox syncing is built around those two ecosystems. Small teams that want one affordable, all-in-one tool for contacts, light pipeline tracking, and social context, rather than a sprawling suite of specialized point solutions, are the clearest fit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex sales organizations, multi-stage approval workflows, or the need for deep customization and role-based permissioning will likely outgrow Nimble quickly. Its feature set is intentionally streamlined, so organizations that require advanced forecasting, territory management, or heavily branched automation logic are better served by platforms built specifically for that scale.$q$, $q$Companies that depend on an extensive third-party app marketplace or need deep, code-level customization of objects and workflows may also find Nimble limiting compared to more extensible platforms. Teams with highly specialized industry requirements, such as regulated financial services workflows or complex manufacturing sales cycles, may need purpose-built CRMs with compliance features Nimble does not offer.$q$, $q$Businesses without much reliance on Google Workspace or Microsoft 365 may find some of Nimble's most convenient integrations less useful, since much of its productivity value comes from that syncing. Organizations looking for a free CRM tier for long-term use should also note that Nimble is positioned as a paid product with a trial period rather than an ongoing free plan.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Nimble's foundation is its unified contact record, which merges data from email, calendar events, and public social profiles into a single timeline for each person or company. This gives users context on past interactions before a call or email, without needing to jump between separate tools or manually reconstruct the relationship history.$q$, $q$The Nimble Prospector browser extension is one of its signature capabilities, letting users hover over a name on LinkedIn or a company website and instantly see whether that contact already exists in Nimble, along with the option to add or update the record on the spot. Paired with simple deal boards, task reminders, and group email templates, teams can move from research to outreach to follow-up inside one connected workflow.$q$, $q$Beyond core contact and pipeline tools, Nimble includes segmentation and tagging for organizing contact lists, basic reporting on deals and activity, and mobile apps for managing relationships away from a desk. Calendar and inbox sync with Google Workspace and Microsoft 365 keeps meetings and messages tied to the right contact automatically, reducing the manual logging that slows teams down in heavier CRMs.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f3558245-b91d-4875-b0dc-3842ac4f3805', $q$the-nimble-experience$q$, $q$The Nimble Experience$q$, 2, ARRAY[$q$Day-to-day, Nimble feels less like a rigid database and more like a smart address book that keeps enriching itself as a team works. New users typically start by connecting their email and calendar, installing the browser extension, and importing an existing contact list, after which the platform begins surfacing social and company context automatically as records are viewed.$q$, $q$The interface favors a small number of clear views, contacts, deals, and a unified inbox-style stream, over deep menus of configuration screens. This makes onboarding faster for non-technical teams, though it also means power users looking for elaborate custom fields, complex automation builders, or granular permission structures will hit the edges of what the product offers sooner than they would with an enterprise CRM.$q$, $q$Support resources include help documentation, webinars, and customer support channels aimed at small business users rather than dedicated enterprise account teams. Overall, the experience is tuned for teams that want to spend their time on relationships and outreach rather than on administering the CRM itself, trading some depth of customization for speed of adoption and day-to-day simplicity.$q$]::text[], 4);
