INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cad47068-0db8-4866-8882-42d54432595e', $q$Remote Monitoring and Management$q$, $q$Continuous, real-time visibility into device health, performance metrics, and software inventory across Windows, macOS, and Linux endpoints.$q$, 0);
