INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b704ca00-ce10-434d-b1f3-abb303ffa4e4', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Encrypted password vault$q$, $q$Stores logins, notes, and payment details in a vault encrypted with the XChaCha20 cipher, synced securely across a user's devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Password generator$q$, $q$Creates strong, random passwords with customizable length and character rules to replace weak or reused credentials.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Autofill$q$, $q$Automatically fills saved usernames, passwords, and card details into browser and app login forms to speed up sign-ins.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Data breach scanner$q$, $q$Checks whether email addresses or passwords stored in the vault have appeared in known data breaches and alerts the user.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Password health check$q$, $q$Scans the vault for weak, reused, or outdated passwords and recommends which credentials to update first.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Secure item sharing$q$, $q$Lets users share individual logins or notes with another person without exposing the rest of the vault.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Multi-factor authentication$q$, $q$Adds an extra verification step beyond the master password to help protect the vault from unauthorized access.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Secure notes and card storage$q$, $q$Stores sensitive information such as payment cards, identity documents, and free-form notes alongside passwords.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Admin console (Business)$q$, $q$Gives administrators visibility into team password health and control over shared folders and user access.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Cross-platform apps$q$, $q$Provides apps and browser extensions for Windows, macOS, iOS, and Android to keep the vault accessible everywhere.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Clean, easy-to-use interface that is approachable for first-time password manager users$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Modern XChaCha20 encryption and a free tier for basic password storage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Useful security tools like breach scanning and password health checks built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Consistent apps and browser extensions across major desktop and mobile platforms$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Family and Business plans support shared vault items and centralized management$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Closed-source codebase may concern users who prefer fully auditable open-source tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Fewer advanced customization options compared to some power-user-focused competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Business plan lacks the deep identity and access management depth of enterprise-grade IAM platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Some premium features require an annual commitment to get the lowest advertised price$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Autofill occasionally needs manual confirmation on nonstandard or custom login forms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Is NordPass free to use?$q$, $q$Yes, NordPass offers a free plan that covers core password storage, generation, and autofill on one device type at a time. Paid Premium, Family, and Business plans add multi-device sync, sharing, and additional features.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$How does NordPass encrypt my data?$q$, $q$NordPass encrypts vault data using the XChaCha20 cipher, and your master password is required to decrypt it locally on your device, meaning NordPass itself does not have access to your stored passwords in plaintext.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Can I share passwords with family members or coworkers?$q$, $q$Yes, NordPass supports secure sharing of individual logins and notes, and the Family and Business plans add shared folders so groups can access designated credentials without exposing an entire personal vault.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Does NordPass work on mobile devices?$q$, $q$Yes, NordPass has native apps for iOS and Android in addition to Windows and macOS apps and browser extensions, with biometric unlock supported on compatible devices.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Is NordPass related to NordVPN?$q$, $q$Yes, NordPass is developed by Nord Security, the same company that makes NordVPN and NordLocker, and it can be bundled with other Nord Security products under one account.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Everyday personal password management$q$, $q$An individual replaces browser-saved or reused passwords with unique, generated credentials stored in an encrypted vault with autofill.$q$, $q$Individual consumers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Shared household logins$q$, $q$A family shares streaming, utility, and other household account logins securely instead of texting passwords or reusing the same ones.$q$, $q$Families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Small team password hygiene$q$, $q$A small business gives employees managed vaults and shared folders while an admin monitors password health across the organization.$q$, $q$Small business teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Consolidating a Nord Security subscription$q$, $q$An existing NordVPN customer adds NordPass to manage passwords under the same account and billing relationship they already use.$q$, $q$Existing Nord Security customers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Password storage on one device type","Password generator","Autofill","Basic security features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Premium$q$, $q$From around $1.69/month$q$, $q$Billed annually$q$, $q$["Unlimited device sync","Data breach scanner","Password health check","Secure item sharing","Secure notes and card storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Family$q$, $q$From around $3.09/month$q$, $q$Billed annually$q$, $q$["Up to 6 individual Premium accounts","Shared folders","All Premium features per member","Centralized family billing"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$Business$q$, $q$Per-user pricing, contact for details$q$, $q$Billed annually$q$, $q$["Admin console","Team password health reporting","Shared folders for teams","Centralized user management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$NordPass is a password manager built by Nord Security, the same company behind NordVPN and NordLocker. Launched in 2019, it was designed to give everyday users and businesses a straightforward way to generate, store, and autofill passwords without having to remember dozens of complex login combinations. The product stores credentials in an encrypted vault that syncs across a user's devices, protected by a master password that never leaves the local device in plaintext.$q$, $q$At its core, NordPass uses the XChaCha20 encryption algorithm, a modern cipher chosen for its speed and security profile compared to older standards used by some competitors. Beyond passwords, the vault can hold secure notes, credit card details, and personal identification information, letting it double as a general-purpose secure storage tool rather than a single-purpose password vault.$q$, $q$NordPass positions itself as an accessible entry point into password management, with a free tier for individuals and paid Premium, Family, and Business tiers for people who want multi-device sync, sharing, and administrative controls. Its close ties to the broader Nord Security ecosystem also make it an easy add-on for existing NordVPN subscribers who want to consolidate their security tools under one brand.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$who-nordpass-is-for$q$, $q$Who NordPass Is For$q$, 2, ARRAY[$q$NordPass suits individuals who want a simple, no-fuss password manager that works out of the box. Its clean interface and short setup flow make it a good fit for people who have never used a password manager before and are looking for an easy first step toward better password hygiene, rather than a deeply configurable power-user tool.$q$, $q$Families are another strong fit, since the Family plan allows a household to share select logins and secure notes across multiple accounts while keeping other vault items private. Small businesses and teams that need centralized visibility into employee password practices, without standing up a full identity and access management stack, can also benefit from the Business plan's admin dashboard and reporting.$q$, $q$Existing Nord Security customers, particularly NordVPN subscribers, may find NordPass appealing simply because it lives in the same account ecosystem and billing relationship they already use, reducing the friction of adopting a separate password manager from an unfamiliar vendor.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with mature identity programs that require deep single sign-on integrations, granular conditional access policies, or directory-level provisioning may find NordPass Business less capable than dedicated enterprise identity and access management platforms built specifically for that scale.$q$, $q$Users who prioritize open-source, self-hostable software for auditability reasons may prefer alternatives that publish their full client and server code for independent review, since NordPass's core codebase is closed source even though it has undergone independent security audits.$q$, $q$Highly technical users who want extensive customization of vault organization, custom fields, or advanced automation features may find some competing password managers offer more flexibility, since NordPass intentionally favors simplicity over configurability in its interface design.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$NordPass's core feature set centers on the encrypted vault itself: password storage, a built-in password generator for creating strong unique credentials, and browser and app autofill so users rarely need to type a saved password manually. The vault also supports secure notes and payment card storage, extending its usefulness beyond simple login management.$q$, $q$Security-monitoring features round out the core offering, including a data breach scanner that checks whether stored email addresses or passwords have appeared in known breaches, and a password health check that flags weak, reused, or old passwords across the vault. Multi-factor authentication options add another layer of protection on top of the master password.$q$, $q$For shared use, NordPass supports secure item sharing between individual users and, on Family and Business plans, shared folders that let multiple people access designated logins without exposing a person's entire vault. Business plans add an admin console for managing user access and reviewing organization-wide password health.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', $q$the-nordpass-experience$q$, $q$The NordPass Experience$q$, 2, ARRAY[$q$Getting started with NordPass is quick: creating an account, choosing a master password, and installing the browser extension or desktop app typically takes only a few minutes. The onboarding flow guides new users through importing existing passwords from a browser or another password manager, which lowers the barrier to switching.$q$, $q$Across platforms, the apps for Windows, macOS, iOS, and Android maintain a consistent, uncluttered design, and biometric unlock (fingerprint or face recognition) is supported on mobile and compatible desktop hardware for faster daily access. Browser extensions handle autofill reliably on most common sites, though like any password manager it occasionally needs manual confirmation on nonstandard login forms.$q$, $q$Overall, the day-to-day experience feels lightweight rather than feature-heavy, which is consistent with NordPass's positioning as an approachable password manager. Users who want a tool that quietly handles password hygiene in the background, with occasional visits to the health dashboard, tend to have the smoothest experience with it.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a6135772-7dd2-43ef-9ed6-959bed72bcfd', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
