INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Visual sales pipeline$q$, $q$A drag-and-drop board view of deals organized by stage, giving reps and managers an at-a-glance view of pipeline health and next actions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Contact and company management$q$, $q$Centralized records that combine communication history, notes, tasks, and associated deals for every contact and company.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Built-in email marketing$q$, $q$Campaign creation and template-based email sends with open and click tracking that surfaces directly on the contact timeline.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Sales automation and reminders$q$, $q$Automated task creation, lead assignment rules, and follow-up reminders that help reduce manual chasing of next steps.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Reporting and forecasting$q$, $q$Pipeline and rep performance reports along with revenue forecasting to help managers track progress toward targets.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Mobile apps$q$, $q$Native iOS and Android apps that let reps update deals, log calls, and check pipeline status while working in the field.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Customizable pipelines$q$, $q$Support for multiple pipelines and stages so different teams or product lines can reflect their own sales process.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Integrations and API$q$, $q$Native connections to tools like Google Workspace, Microsoft 365, and QuickBooks, plus an API for building custom connections.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Email templates$q$, $q$Reusable email templates that speed up outreach for both individual sales emails and broader marketing campaigns.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Combines pipeline CRM and email marketing in a single platform, reducing tool sprawl for small teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Visual, drag-and-drop pipeline interface that is easy for new reps to learn quickly$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Reasonably fast setup and onboarding compared to larger enterprise CRM systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Native mobile apps allow reps to manage deals and contacts away from their desk$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Reporting and forecasting tools give managers useful pipeline visibility without heavy configuration$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$No perpetual free plan, so smaller or budget-constrained teams must commit to a paid tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Marketing automation capabilities are more basic than dedicated marketing automation platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$May feel limiting for larger organizations needing complex permissions or workflow customization$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Advanced customization of pipeline logic and automation can be less flexible than some competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Deeper integrations beyond the native list may require relying on the API or third-party connectors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$What is Nutshell used for?$q$, $q$Nutshell is a CRM used by small business sales teams to manage contacts, track deals through a visual pipeline, automate follow-up tasks, and run email marketing campaigns from the same platform.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Does Nutshell offer a free plan?$q$, $q$Nutshell does not offer a permanent free plan, but it does provide a free trial period so teams can test the CRM and email marketing features before subscribing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Does Nutshell include email marketing tools?$q$, $q$Yes, Nutshell includes built-in email marketing capabilities such as campaign creation, templates, and engagement tracking, alongside its core CRM pipeline features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Is Nutshell suitable for large enterprises?$q$, $q$Nutshell is primarily built for small and midsize sales teams; larger enterprises with complex workflow, permission, or customization needs may find it more limited than enterprise-focused CRM platforms.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Does Nutshell have mobile apps?$q$, $q$Yes, Nutshell offers native mobile apps for both iOS and Android so sales reps can manage deals and contacts while working outside the office.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Managing a small business sales pipeline$q$, $q$Sales teams use Nutshell's visual pipeline to track deals from initial contact through close, keeping everyone aligned on stage and next steps.$q$, $q$Small business sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Running email marketing campaigns from the CRM$q$, $q$Teams design and send email campaigns to segmented contact lists directly within Nutshell, tracking engagement without a separate marketing tool.$q$, $q$Small marketing and sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Forecasting revenue and tracking rep performance$q$, $q$Sales managers rely on Nutshell's reporting to monitor pipeline health, compare rep performance, and forecast upcoming revenue.$q$, $q$Sales managers and team leads$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Centralizing customer and prospect communication$q$, $q$Businesses consolidate contact history, notes, and follow-up tasks in one place so reps have full context before every interaction.$q$, $q$B2B service and product companies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Foundation$q$, $q$Approximately $16/user/month$q$, $q$Billed annually$q$, $q$["Sales pipeline management","Contact and company records","Basic reporting","Mobile apps"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Growth$q$, $q$Mid-tier pricing above Foundation$q$, $q$Billed annually$q$, $q$["Everything in Foundation","Email marketing campaigns","Sales automation","Advanced reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$Pro / Enterprise$q$, $q$Contact for pricing$q$, $q$Billed annually$q$, $q$["Everything in Growth","Advanced customization","Additional integrations","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Nutshell is a customer relationship management platform designed specifically for small and midsize business sales teams that need more structure than a spreadsheet but less complexity than an enterprise CRM suite. Built around a visual sales pipeline, contact management, and reporting tools, Nutshell aims to give sales teams a single place to track leads, log activity, and forecast revenue without a steep learning curve or a large administrative overhead.$q$, $q$What differentiates Nutshell from many pipeline-focused competitors is its built-in email marketing functionality, which lets teams design and send campaigns, build simple automation sequences, and track engagement directly from the same platform where deals and contacts already live. This combination is aimed at smaller organizations that do not want to pay for and integrate two separate systems, one for sales pipeline management and another for outbound email marketing.$q$, $q$The platform is delivered as a web application with companion mobile apps for iOS and Android, so reps can update deals, log calls, and check pipeline status from the field. Nutshell also exposes an API and a set of native integrations with popular tools like Google Workspace, Microsoft 365, QuickBooks, and various support and marketing platforms, positioning it as a practical hub rather than a closed system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$who-nutshell-is-for$q$, $q$Who Nutshell Is For$q$, 2, ARRAY[$q$Nutshell is generally best suited to small business sales teams, typically ranging from a handful of reps to a few dozen, that need a shared pipeline view and consistent process without the configuration burden of a large enterprise CRM. Teams transitioning off spreadsheets, shared inboxes, or a very basic contact manager often find Nutshell's structure a natural next step.$q$, $q$It also appeals strongly to organizations that want sales and marketing outreach handled in one tool rather than stitching together a CRM and a separate email marketing platform. Agencies, service businesses, manufacturers, and B2B companies with defined sales cycles tend to be a good fit, since Nutshell's pipeline stages, task reminders, and reporting are built around a fairly standard opportunity-to-close workflow.$q$, $q$Sales managers who want visibility into rep activity and forecasted revenue without building custom dashboards from scratch are another core audience, as are teams that value a shorter onboarding timeline and prefer a CRM that can be configured by an internal admin rather than requiring a dedicated CRM administrator or consultant.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-department sales operations, territory management needs, or heavily customized approval workflows may find Nutshell's feature set more limited than platforms built specifically for enterprise-scale deployments. Organizations that need extensive configurability of objects, permissions, and workflow logic will likely outgrow it.$q$, $q$Companies whose primary need is advanced marketing automation, such as complex multi-channel journeys, sophisticated lead scoring models, or deep behavioral segmentation, may find Nutshell's built-in marketing tools more basic than what dedicated marketing automation platforms provide. Teams with those requirements are often better served by a specialized marketing platform paired with a CRM via integration.$q$, $q$Very small solo operators or freelancers with only a few contacts and no real pipeline to manage may also find a full CRM like Nutshell more than they need, since there is no perpetual free tier and the value proposition depends on having an actual sales process and team to coordinate around.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Nutshell offers a visual, drag-and-drop sales pipeline that lets reps and managers see every deal's stage, value, and next steps at a glance. Contact and company records consolidate communication history, notes, and related deals, while customizable pipelines support different sales processes for different teams or products within the same account.$q$, $q$The platform's email marketing module allows users to build campaigns, design templates, and send bulk or triggered emails to segments of their contact list, with engagement tracking that feeds back into the CRM timeline so sales reps can see which prospects opened or clicked. Sales automation features, including task reminders, lead assignment rules, and simple sequences, help reduce manual follow-up work.$q$, $q$Reporting and forecasting tools give managers pipeline health metrics, rep performance comparisons, and revenue projections, while native mobile apps, an open API, and integrations with email, calendar, accounting, and support tools round out the platform so it can sit at the center of a small sales operation rather than in isolation.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de6eb85c-e884-4464-97df-4e4c4479c1d0', $q$the-nutshell-experience$q$, $q$The Nutshell Experience$q$, 2, ARRAY[$q$Day to day, using Nutshell feels closer to a lightweight, visually oriented sales tool than a heavyweight enterprise system. The pipeline board is the natural home screen for most reps, and moving deals between stages, logging activity, and setting follow-up tasks is designed to take just a few clicks rather than navigating through multiple configuration screens.$q$, $q$New users generally find the onboarding process manageable, with setup wizards, templates, and support resources aimed at getting a team's pipeline, contacts, and email templates configured within days rather than weeks. Customer support is available through in-app channels and a knowledge base, and Nutshell has built a reputation among small business buyers for being more approachable than some of the larger CRM incumbents.$q$, $q$The tradeoff for that simplicity is that power users chasing highly customized workflows, advanced automation branching, or granular permission structures may occasionally hit the platform's ceiling. For its target audience, however, the overall experience tends to prioritize speed to value and day-to-day usability over exhaustive configurability.$q$]::text[], 4);
